class Solution {
    public String baseNeg2(int n) {
        if (n == 0) return "0";
        StringBuilder sb = new StringBuilder();
        while (n != 0) {
            int remainder = n % (-2);
            if (remainder < 0) {
                remainder += 2;
                n = (n - remainder) / (-2);
            } else {
                n = n / (-2);
            }
            sb.append(remainder);
        }
        return sb.reverse().toString();
    }
}

